using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Breaking change #1: EF 9 removed HasIndex for Cosmos (no secondary indexes).
            // Removed: b.HasIndex(b => b.Name);

            // Breaking change #2: EF 9 renamed "Discriminator" to "$type".
            // Preserve compatibility with existing documents that use "Discriminator".
            b.HasDiscriminator<string>("Discriminator");

            // Breaking change #3: EF 9 changed id format from "EntityType|Key" to just "Key".
            // Preserve compatibility with existing "Blog|1" ids in Cosmos.
            b.HasPartitionKey(x => x.Id);
            b.Property(x => x.Id)
                .ToJsonProperty("id")
                .HasValueGenerator<LegacyCosmosIdGenerator>();
        });
    }
}

// Preserves the legacy "Blog|<key>" id format used by EF Core 8 and earlier.
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(EntityEntry entry)
        => $"{entry.Metadata.ShortName()}|{Guid.NewGuid()}";
}

class Blog { public string Id { get; set; } public string Name { get; set; } }

