class SyncJob
{
    void Run(BlogContext context)
    {
        // Breaking change #4: EF 9 uses parameterized queries by default, and
        // sync I/O now throws by default on Cosmos. Use async methods instead.

        // Breaking change #5: Raw SQL must reference "$type" (or "Discriminator"
        // if you configured HasDiscriminator("Discriminator") as above).
        // With the compat fix in BlogContext, existing queries still work:
        //   SELECT * FROM c WHERE c.Discriminator = 'Blog'

        var blogs = context.Blogs.ToList();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        context.SaveChanges();
    }
}

